<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***ManualNRPFormatFixer*FixspecificNRPrecordsthatneedmanualintervention*/require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/Database.php';require_once__DIR__.'/APIResponse.php';classManualNRPFixer{private$pdo;publicfunction__construct(){$db=Database::getInstance();$this->pdo=$db->getConnection();}/***FixspecificproblematicNRPrecords*/publicfunctionfixSpecificNRP(){$fixes=[['id'=>282,'nama'=>'REYMESTAAMBARITA,S.Kom.','current_nrp'=>'198111252014122004','proposed_nrp'=>'84112520'/ExtractfromNIP:1981-11-25],['id'=>305,'nama'=>'NENENGGUSNIARTI','current_nrp'=>'197008291993032002','proposed_nrp'=>'70082920'/ExtractfromNIP:1970-08-29],['id'=>511,'nama'=>'FERNANDOSILALAHI,A.Md.','current_nrp'=>'198112262024211002','proposed_nrp'=>'81122620'/ExtractfromNIP:1981-12-26]];$results=[];$fixed_count=0;forforeach($fixesas$fix){$result=$this->applyManualFix($fix);$results[]=$result;if($result['status']==='fixed'){$fixed_count++;}}return['success'=>true,'message'=>"Manuallyfixed{$fixed_count}NRPrecords",'results'=>$results,'fixed_count'=>$fixed_count,'timestamp'=>date('c')];}/***Applymanualfixforspecificrecord*/privatefunctionapplyManualFix($fix){$id=$fix['id'];$current_nrp=$fix['current_nrp'];$proposed_nrp=$fix['proposed_nrp'];/CheckifproposedNRPalreadyexistsif($this->nrpExists($proposed_nrp,$id)){return['id'=>$id,'nama'=>$fix['nama'],'current_nrp'=>$current_nrp,'proposed_nrp'=>$proposed_nrp,'status'=>'conflict','message'=>'ProposedNRPconflictswithexistingrecord'];}try{$update_sql="UPDATEpersonilSETnrp=?,updated_at=NOW()WHEREid=?";$stmt=$this->pdo->prepare($update_sql);$result=$stmt->execute([$proposed_nrp,$id]);if($result){return['id'=>$id,'nama'=>$fix['nama'],'old_nrp'=>$current_nrp,'new_nrp'=>$proposed_nrp,'status'=>'fixed','message'=>'NRPmanuallycorrectedsuccessfully'];}else{return['id'=>$id,'nama'=>$fix['nama'],'current_nrp'=>$current_nrp,'status'=>'error','message'=>'FailedtoupdateNRP'];}}catch(Exception$e){return['id'=>$id,'nama'=>$fix['nama'],'current_nrp'=>$current_nrp,'status'=>'error','message'=>'Databaseerror:'.$e->getMessage()];}}/***CheckifNRPalreadyexists(excludingcurrentrecord)*/privatefunctionnrpExists($nrp,$exclude_id){$sql="SELECTCOUNT(*)ascountFROMpersonilWHEREnrp=?ANDid!=?ANDis_deleted=0";$stmt=$this->pdo->prepare($sql);$stmt->execute([$nrp,$exclude_id]);return$stmt->fetch()['count']>0;}/***VerifyfinalNRPformatstatus*/publicfunctionverifyFinalNRPStatus(){$sql="SELECTCOUNT(*)astotal_invalidFROMpersonilWHEREis_deleted=0ANDnrpISNOTnullANDnrp!=''ANDnrpNOTREGEXP'^[0-9]{8,9}$'";$stmt=$this->pdo->query($sql);$total_invalid=$stmt->fetch()['total_invalid'];return['success'=>$total_invalid===0,'total_invalid'=>(int)$total_invalid,'all_valid'=>$total_invalid===0,'timestamp'=>date('c')];}}/Executeifaccesseddirectlyif(basename($_SERVER['PHP_SELF'])===basename(__FILE__)){header('Content-Type:application/json');try{$fixer=newManualNRPFixer();/Applymanualfixes$fix_result=$fixer->fixSpecificNRP();/Verifyfinalstatus$verify_result=$fixer->verifyFinalNRPStatus();echojson_encode(APIResponse::success(['fix_result'=>$fix_result,'verification'=>$verify_result],'ManualNRPfixcompleted'));}catch(Exception$e){echojson_encode(APIResponse::error($e->getMessage(),500));}}?>
